require"UI.UIBase"require"UI.UIBlock"UI_Buy_Loading=UIBase:Inherit()function UI_Buy_Loading:OnCreate()UI_Buy_Loading.Inst=self;self.timerMgr=TimerMgr:Init()self.round=self.transform:Find('loading'):Find('flower'):Find('round')self.pre_t=0 end;function UI_Buy_Loading:OnShow(a,b)self.transform:SetAsLastSibling()self.transform.gameObject:SetActive(true)self:AnimAlphaIn(self.transform,{x=0,y=0},0.15)a()self.timerMgr:LoopFrame(1,-1,function()local c=UnityEngine.Time.time-self.pre_t;self.pre_t=UnityEngine.Time.time;if c>1 then c=0 end;self.round:Rotate(0,0,-c*180)end)end;function UI_Buy_Loading:OnClose(a)self:AnimAlphaOut(self.transform,{x=0,y=0},0.15,0,function()a()self.transform.gameObject:SetActive(false)self.timerMgr:ClearAllTimers()end)end;return UI_Buy_Loading